from typing import Any, Dict, List, Tuple, Optional


MAGIC = b"GSQ1"
VERSION = 1

MSG_STATUS_REQ = 1
MSG_STATUS_RESP = 2
MSG_PING = 3
MSG_PONG = 4

FLAG_COMPRESSED = 1 << 0
FLAG_CHUNKED = 1 << 1

MAX_DATAGRAM = 1200
HEADER_FMT = "!4sBBBBIHHHH"
HEADER_SIZE = struct.calcsize(HEADER_FMT)
CHUNK_HDR_FMT = "!IHHH"
CHUNK_HDR_SIZE = struct.calcsize(CHUNK_HDR_FMT)

DEFAULT_CHUNK_PAYLOAD = MAX_DATAGRAM - HEADER_SIZE - CHUNK_HDR_SIZE
DEFAULT_SINGLE_PAYLOAD = MAX_DATAGRAM - HEADER_SIZE

MAX_RESPONSE_BYTES = 2_000_000
MAX_CHUNKS = 4096

SERVER_TICK_HZ = 20


def now_ms() -> int:
    return int(time.time() * 1000)


def rand_token(n: int = 16) -> str:
    return "".join(random.choice(string.ascii_letters + string.digits) for _ in range(n))


def build_header(msg_type: int, flags: int, req_id: int, payload_len: int,
                 total_chunks: int = 1, chunk_index: int = 0,
                 chunk_len: int = 0, reserved: int = 0) -> bytes:
    return struct.pack(
        HEADER_FMT,
        MAGIC,
        VERSION,
        msg_type,
        flags & 0xFF,
        reserved & 0xFF,
        req_id & 0xFFFFFFFF,
        payload_len & 0xFFFF,
        total_chunks & 0xFFFF,
        chunk_index & 0xFFFF,
        chunk_len & 0xFFFF,
    )


def parse_header(data: bytes) -> Optional[Tuple[int, int, int, int, int, int, int, int]]:
    if len(data) < HEADER_SIZE:
        return None
    magic, ver, msg_type, flags, reserved, req_id, payload_len, total_chunks, chunk_index, chunk_len = struct.unpack(
        HEADER_FMT, data[:HEADER_SIZE]
    )
    if magic != MAGIC or ver != VERSION:
        return None
    return msg_type, flags, req_id, payload_len, total_chunks, chunk_index, chunk_len, reserved


def encode_status_payload(status: Dict[str, Any]) -> bytes:
    b = json.dumps(status, separators=(",", ":"), ensure_ascii=False).encode("utf-8")
    return b


def compress_payload(payload: bytes) -> bytes:
    return zlib.compress(payload, level=6)


def chunk_payload(payload: bytes, chunk_size: int) -> List[bytes]:
    if chunk_size <= 0:
        return [payload]
    return [payload[i:i + chunk_size] for i in range(0, len(payload), chunk_size)]


class GameState:
    def __init__(self):
        self.server_id = rand_token(12)
        self.name = "Example Game Server"
        self.map = "arena_01"
        self.mode = "deathmatch"
        self.max_players = 64
        self.players: List[Dict[str, Any]] = []
        self.start_time_ms = now_ms()
        self.tick = 0
        self.rules: Dict[str, Any] = {
            "friendly_fire": False,
            "time_limit_sec": 900,
            "score_limit": 50,
        }
        self.world: Dict[str, Any] = {
            "weather": "clear",
            "time_of_day": "noon",
        }

    def add_fake_players(self, n: int):
        for i in range(n):
            self.players.append({
                "id": rand_token(8),
                "name": f"Player{i+1}",
                "score": random.randint(0, 100),
                "ping": random.randint(10, 120),
                "team": random.choice(["red", "blue", "none"]),
                "pos": [round(random.uniform(-100, 100), 2), round(random.uniform(-100, 100), 2), 0.0],
            })

    def update(self):
        self.tick += 1
        if self.tick % (SERVER_TICK_HZ * 10) == 0:
            self.map = random.choice(["arena_01", "arena_02", "facility", "canyon"])
            self.mode = random.choice(["deathmatch", "ctf", "king_of_the_hill"])
        for p in self.players:
            p["score"] = int(p["score"]) + random.randint(-1, 2)
            p["ping"] = max(1, int(p["ping"]) + random.randint(-2, 3))

    def status(self) -> Dict[str, Any]:
        uptime_ms = now_ms() - self.start_time_ms
        return {
            "server": {
                "id": self.server_id,
                "name": self.name,
                "map": self.map,
                "mode": self.mode,
                "tick": self.tick,
                "uptime_ms": uptime_ms,
                "players": {
                    "online": len(self.players),
                    "max": self.max_players,
                },
            },
            "rules": self.rules,
            "world": self.world,
            "players": self.players,
        }


class UDPGameServer(asyncio.DatagramProtocol):
    def __init__(self, state: GameState,
                 compress: bool = True,
                 allow_large: bool = True,
                 max_datagram: int = MAX_DATAGRAM):
        self.state = state
        self.compress = compress
        self.allow_large = allow_large
        self.max_datagram = max_datagram
        self.transport: Optional[asyncio.DatagramTransport] = None
        self._sock: Optional[socket.socket] = None

    def connection_made(self, transport: asyncio.BaseTransport) -> None:
        self.transport = transport  # type: ignore[assignment]
        try:
            self._sock = self.transport.get_extra_info("socket")
            if self._sock:
                self._sock.setsockopt(socket.SOL_SOCKET, socket.SO_SNDBUF, 4 * 1024 * 1024)
                self._sock.setsockopt(socket.SOL_SOCKET, socket.SO_RCVBUF, 4 * 1024 * 1024)
        except Exception:
            pass

    def datagram_received(self, data: bytes, addr: Tuple[str, int]) -> None:
        h = parse_header(data)
        if not h:
            return
        msg_type, flags, req_id, payload_len, total_chunks, chunk_index, chunk_len, reserved = h

        if msg_type == MSG_PING:
            resp = build_header(MSG_PONG, 0, req_id, 0, 1, 0, 0, 0)
            self._send(resp, addr)
            return

        if msg_type != MSG_STATUS_REQ:
            return

        payload = b""
        if payload_len:
            payload = data[HEADER_SIZE:HEADER_SIZE + payload_len]

        want_compress = self.compress
        want_chunked = self.allow_large

        status = self.state.status()
        out = encode_status_payload(status)
        if len(out) > MAX_RESPONSE_BYTES:
            out = json.dumps({"error": "response_too_large", "max_bytes": MAX_RESPONSE_BYTES}, separators=(",", ":")).encode("utf-8")

        out_flags = 0
        if want_compress:
            comp = compress_payload(out)
            if len(comp) < len(out):
                out = comp
                out_flags |= FLAG_COMPRESSED

        if not want_chunked and len(out) > (self.max_datagram - HEADER_SIZE):
            out = json.dumps({"error": "response_too_large_for_single_datagram"}, separators=(",", ":")).encode("utf-8")

        if len(out) <= (self.max_datagram - HEADER_SIZE):
            hdr = build_header(MSG_STATUS_RESP, out_flags, req_id, len(out), 1, 0, len(out), 0)
            self._send(hdr + out, addr)
            return

        out_flags |= FLAG_CHUNKED
        chunk_payload_size = self.max_datagram - HEADER_SIZE - CHUNK_HDR_SIZE
        chunks = chunk_payload(out, chunk_payload_size)
        total = len(chunks)
        if total > MAX_CHUNKS:
            err = json.dumps({"error": "too_many_chunks", "max_chunks": MAX_CHUNKS}, separators=(",", ":")).encode("utf-8")
            hdr = build_header(MSG_STATUS_RESP, 0, req_id, len(err), 1, 0, len(err), 0)
            self._send(hdr + err, addr)
            return

        crc = zlib.crc32(out) & 0xFFFFFFFF
        full_len = len(out)

        for idx, c in enumerate(chunks):
            chunk_hdr = struct.pack(CHUNK_HDR_FMT, crc, full_len & 0xFFFF, (full_len >> 16) & 0xFFFF, idx & 0xFFFF)
            hdr = build_header(MSG_STATUS_RESP, out_flags, req_id, len(c) + CHUNK_HDR_SIZE, total, idx, len(c) + CHUNK_HDR_SIZE, 0)
            self._send(hdr + chunk_hdr + c, addr)

    def _send(self, data: bytes, addr: Tuple[str, int]) -> None:
        if not self.transport:
            return
        try:
            self.transport.sendto(data, addr)
        except Exception:
            pass


async def state_loop(state: GameState):
    interval = 1.0 / SERVER_TICK_HZ
    while True:
        state.update()
        await asyncio.sleep(interval)


